#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\pujols\Desktop\learn_\node_modules\.pnpm\standard@17.1.0\node_modules\standard\bin\node_modules;C:\Users\pujols\Desktop\learn_\node_modules\.pnpm\standard@17.1.0\node_modules\standard\node_modules;C:\Users\pujols\Desktop\learn_\node_modules\.pnpm\standard@17.1.0\node_modules;C:\Users\pujols\Desktop\learn_\node_modules\.pnpm\node_modules;C:\Users\pujols\Desktop\learn_\node_modules;C:\Users\pujols\Desktop\node_modules;C:\Users\pujols\node_modules;C:\Users\node_modules;C:\node_modules;C:\Users\pujols\desktop\learn_\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/Users/pujols/Desktop/learn_/node_modules/.pnpm/standard@17.1.0/node_modules/standard/bin/node_modules:/mnt/c/Users/pujols/Desktop/learn_/node_modules/.pnpm/standard@17.1.0/node_modules/standard/node_modules:/mnt/c/Users/pujols/Desktop/learn_/node_modules/.pnpm/standard@17.1.0/node_modules:/mnt/c/Users/pujols/Desktop/learn_/node_modules/.pnpm/node_modules:/mnt/c/Users/pujols/Desktop/learn_/node_modules:/mnt/c/Users/pujols/Desktop/node_modules:/mnt/c/Users/pujols/node_modules:/mnt/c/Users/node_modules:/mnt/c/node_modules:/mnt/c/Users/pujols/desktop/learn_/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../../bin/cmd.cjs" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../../bin/cmd.cjs" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../../bin/cmd.cjs" $args
  } else {
    & "node$exe"  "$basedir/../../bin/cmd.cjs" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
